        "editorMode": "code",
        "format": "time_series",
        "hide": false,
        "rawQuery": true,
        "rawSql": "   SELECT reading.measurement_time AS \"time\",\n          reading.value AS \"Lecturas\",\n          sensor.name AS \"Sensor\"\n     FROM res_partner_sensor_reading reading\nLEFT JOIN mdm_measurement_device device ON device.id = reading.device_id\nLEFT JOIN mdm_measurement_device_sensor sensor ON sensor.id = reading.sensor_id\nLEFT JOIN res_partner partner ON partner.id = reading.partner_id\n    WHERE device.name IN (${devices:sqlstring})\n      AND sensor.name IN (${sensors:sqlstring})\n      AND reading.partner_id = ${partner_id}\n      AND $__timeFilter(reading.measurement_time)\n GROUP BY reading.measurement_time, reading.value, sensor.name\n ORDER BY reading.measurement_time;",
        "refId": "A",
        "sql": {
            "columns": [
            {
                "parameters": [],
                "type": "function"
            }
            ],
